// 计算器工具
// 输入: a (数字), b (数字), operator (运算符)
// 输出: 计算结果

const { a, b, operator } = args;

// 验证输入
if (typeof a !== 'number' || typeof b !== 'number') {
  throw new Error('a 和 b 必须是数字');
}

// 根据运算符执行计算
var result;
switch (operator) {
  case '+':
    result = a + b;
    break;
  case '-':
    result = a - b;
    break;
  case '*':
    result = a * b;
    break;
  case '/':
    if (b === 0) {
      throw new Error('除数不能为零');
    }
    result = a / b;
    break;
  case '**':
    result = Math.pow(a, b);
    break;
  case '%':
    if (b === 0) {
      throw new Error('取模的除数不能为零');
    }
    result = a % b;
    break;
  default:
    throw new Error('不支持的运算符: ' + operator);
}

return {
  expression: a + ' ' + operator + ' ' + b,
  result: result,
  operator: operator
};
